'use client';

import { useState, useMemo } from 'react';
import ProductCard from './ProductCard';
import type { Product } from '../data/mockData';

type ProductWithMeta = Product & {
  cooperativeSlug: string;
  category: string;
  cooperativeName?: string;
};

type ZoneProductGridProps = {
  products: ProductWithMeta[];
};

export default function ZoneProductGrid({ products }: ZoneProductGridProps) {
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);

  const categories = useMemo(
    () => Array.from(new Set(products.map((p) => p.category))).sort(),
    [products],
  );

  const filtered = useMemo(
    () =>
      categoryFilter
        ? products.filter((p) => p.category === categoryFilter)
        : products,
    [products, categoryFilter],
  );

  return (
    <div className="space-y-6">
      {categories.length > 1 && (
        <div className="rounded-2xl border border-white/50 bg-white/80 p-4 shadow-soft">
          <p className="mb-3 text-xs font-medium uppercase tracking-wide text-palmier/70">
            Filtrer par type
          </p>
          <div className="flex flex-wrap gap-2">
            <button
              type="button"
              onClick={() => setCategoryFilter(null)}
              className={`rounded-xl px-4 py-2.5 text-sm font-medium transition ${
                !categoryFilter
                  ? 'bg-terracotta text-white shadow-md'
                  : 'bg-palmier/5 text-palmier hover:bg-palmier/10'
              }`}
            >
              Tous
            </button>
            {categories.map((cat) => (
              <button
                key={cat}
                type="button"
                onClick={() => setCategoryFilter(cat)}
                className={`rounded-xl px-4 py-2.5 text-sm font-medium transition ${
                  categoryFilter === cat
                    ? 'bg-terracotta text-white shadow-md'
                    : 'bg-palmier/5 text-palmier hover:bg-palmier/10'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="rounded-2xl border border-white/50 bg-white/70 p-4 shadow-soft sm:p-6">
        <p className="mb-4 text-sm text-palmier/70">
          {filtered.length} produit{filtered.length > 1 ? 's' : ''} trouvé
          {filtered.length > 1 ? 's' : ''}
        </p>
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {filtered.map((product, index) => (
            <ProductCard
              key={product.id}
              product={product}
              cooperativeSlug={product.cooperativeSlug}
              index={index}
              zoneTag={product.cooperativeName}
            />
          ))}
        </div>
      </div>
    </div>
  );
}
